$base = "https://hiring.bhume.in"
$jobs = @(
  @{url="$base/bhume-starter-kit.zip"; out="F:\BhuMe\bhume-starter-kit.zip"},
  @{url="$base/data/34855_vadnerbhairav_chandavad_nashik/input.geojson"; out="F:\BhuMe\data\vadnerbhairav\input.geojson"},
  @{url="$base/data/34855_vadnerbhairav_chandavad_nashik/imagery.tif"; out="F:\BhuMe\data\vadnerbhairav\imagery.tif"},
  @{url="$base/data/34855_vadnerbhairav_chandavad_nashik/boundaries.tif"; out="F:\BhuMe\data\vadnerbhairav\boundaries.tif"},
  @{url="$base/data/34855_vadnerbhairav_chandavad_nashik/example_truths.geojson"; out="F:\BhuMe\data\vadnerbhairav\example_truths.geojson"},
  @{url="$base/data/12429_malatavadi_chandgad_kolhapur/input.geojson"; out="F:\BhuMe\data\malatavadi\input.geojson"},
  @{url="$base/data/12429_malatavadi_chandgad_kolhapur/imagery.tif"; out="F:\BhuMe\data\malatavadi\imagery.tif"},
  @{url="$base/data/12429_malatavadi_chandgad_kolhapur/boundaries.tif"; out="F:\BhuMe\data\malatavadi\boundaries.tif"},
  @{url="$base/data/12429_malatavadi_chandgad_kolhapur/example_truths.geojson"; out="F:\BhuMe\data\malatavadi\example_truths.geojson"}
)
$runningJobs = $jobs | ForEach-Object {
  $url = $_.url; $out = $_.out
  Start-Job -ScriptBlock { Invoke-WebRequest -Uri $using:url -OutFile $using:out -UseBasicParsing }
}
Write-Host "Downloading $($runningJobs.Count) files..."
$runningJobs | Wait-Job | Out-Null
$runningJobs | ForEach-Object { 
  $state = $_.State
  Write-Host "$($_.Name): $state"
  if ($state -eq "Failed") { Receive-Job $_ }
}

